from hypothesis import given
from hypothesis import strategies as st
from my.error import CommandNotFound


def describe_error_CommandNotFound():
    """l'exception CommandNotFound"""

    def it_dont_know_command_name():
        """ne connaît pas nécessairement la commande fautive"""
        CommandNotFound()

    @given(name=st.text())
    def it_cans_hold_command_name(name: str):
        """peut retenir le nom de la commande"""
        e = CommandNotFound(name)

        assert name in e.message
